import React from 'react';
import ProjectOutflowsTable from './ProjectOutflowsTable';

function BasicTable() {
  // Sample data
  const projectId = 1; // Replace with your project ID
  const sampleOutflows = [
    {
      outflowid: 1,
      location: 'Location 1',
      materialid: 101,
      width: 10,
      lotnumber: 'Lot A',
      quantity: 5,
      date: '2023-09-01',
      cost: 50,
      employee: 'Employee 1',
      project: 1,
    },
    // Add more sample data here...
  ];

  return (
    <div>
      <h1>Basic Table Test</h1>
      <ProjectOutflowsTable projectId={projectId} outflows={sampleOutflows} />
    </div>
  );
}

export default BasicTable;
